// ── Helper lookups ─────────────────────────────
export function getUserName(userId: string | null): string {
  if (!userId) return 'Unassigned';
  return seedUsers.find(u => u.user_id === userId)?.full_name ?? 'Unknown';
}

export function getNotesForEntity(entityType: EntityType, entityId: string): Note[] {
  return seedNotes.filter(n => n.entity_type === entityType && n.entity_id === entityId);
}

export function getCalendarEventsForEntity(entityType: EntityType, entityId: string): CalendarEvent[] {
  return seedCalendarEvents.filter(e => e.entity_type === entityType && e.entity_id === entityId);
}

export function getNextUpcomingEvent(entityType: EntityType, entityId: string): CalendarEvent | undefined {
  return seedCalendarEvents
    .filter(e => e.entity_type === entityType && e.entity_id === entityId && e.status === CalendarEventStatus.UPCOMING)
    .sort((a, b) => new Date(a.scheduled_at).getTime() - new Date(b.scheduled_at).getTime())[0];
}

// ── Go-live automation helper ──────────────────
export function createGoLiveEvent(accountId: string, liveDate: string): CalendarEvent | null {
  // Idempotency: check if event already exists
  const key = `7-day go-live check-in`;
  const existing = seedCalendarEvents.find(
    e => e.entity_type === EntityType.ACCOUNT && e.entity_id === accountId && e.title.includes(key)
  );
  if (existing) return null;

  const account = seedAccounts.find(a => a.account_id === accountId);
  if (!account) return null;

  const checkInDate = new Date(liveDate);
  checkInDate.setDate(checkInDate.getDate() + 7);

  const event: CalendarEvent = {
    event_id: `CE_GL_${accountId}_${Date.now()}`,
    entity_type: EntityType.ACCOUNT,
    entity_id: accountId,
    title: `7-day go-live check-in — ${account.account_name}`,
    scheduled_at: checkInDate.toISOString(),
    created_by_user_id: 'U001',
    notes: 'Auto-generated: Verify adoption, check blockers, review next steps.',
    status: CalendarEventStatus.UPCOMING,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  };

  seedCalendarEvents.push(event);
  return event;
}
